/* Return the largest sum of any contiguous subarray in the vector x.
   Uses Kadane's algorithm for O(n) time and O(1) extra space.
   Exact behavior: returns the maximum subarray sum even if all elements are negative.
*/
int maximumSubarray(std::vector<int> const& x) {
    // Handle empty input – behavior undefined for original, but return 0 for safety
    if (x.empty()) return 0;

    int current = 0;
    int best    = std::numeric_limits<int>::lowest();

    for (int v : x) {
        current = std::max(v, current + v);
        best    = std::max(best, current);
    }
    return best;
}
