19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstring>

/* Return the length of the shortest path from source to dest in the undirected
   graph defined by the adjacency matrix A. A is an NxN row‑major matrix.
   The graph is connected and undirected. */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // distance array, -1 means unvisited
    std::vector<int> dist(N, -1);
    // simple ring buffer queue
    std::vector<int> q(N);
    size_t head = 0, tail = 0;

    dist[source] = 0;
    q[tail++] = source;

    while (head < tail) {
        int u = q[head++];
        int du = dist[u];
        if (u == dest) return du;              // reached destination

        const int* row = &A[u * N];
        for (size_t v = 0; v < N; ++v) {
            if (row[v] && dist[v] == -1) {     // neighbour not visited
                dist[v] = du + 1;
                q[tail++] = static_cast<int>(v);
            }
        }
    }
    // graph is guaranteed connected; unreachable should not happen
    return std::numeric_limits<int>::max();
}
```

