/* Return the average of the vector x.
   Examples:
   input: [1, 8, 4, 5, 1]
   output: 3.8
   input: [2, 2, 2, 3]
   output: 2.25
*/
inline double average(std::vector<double> const& x) {
    // Handle empty vector in the same way as std::reduce: division by zero yields NaN
    if (x.empty())
        return std::numeric_limits<double>::quiet_NaN();

    const std::size_t N = x.size();
    const std::size_t chunk = 256;          // SIMD-friendly block size
    double total = 0.0;

    #pragma omp parallel
    {
        double local = 0.0;
        #pragma omp for schedule(static, chunk) nowait
        for (std::size_t i = 0; i < N; ++i) {
            local += x[i];
        }
        #pragma omp atomic
        total += local;
    }

    return total / static_cast<double>(N);
}
