/* Compute the prefix sum array of the vector x and return its sum.
   The original code first builds an inclusive prefix sum array
   and then sums it. This rewritten version uses the mathematical
   identity

        ∑_{i=0}^{n-1} (∑_{j=0}^{i} x[j]) = ∑_{j=0}^{n-1} x[j] · (n - j)

   which is equivalent to the original but requires a single
   linear pass and no temporary storage. The implementation
   parallelises the weighted sum with OpenMP to utilise all
   available CPU cores.
*/
int64_t sumOfPrefixSum(std::vector<int64_t> const& x) {
    const std::size_t n = x.size();
    int64_t result = 0;

    // Parallel accumulate using a weight of (n - i) for each element.
    #pragma omp parallel for reduction(+:result) schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        result += x[i] * static_cast<int64_t>(n - i);
    }

    return result;
}
