#include <vector>
#include <omp.h>

/* Vector x contains values between 0 and 100, inclusive. Count the number of
   values in [0,10), [10, 20), [20, 30), ... and store the counts in `bins`.
   Example:
   input: [7, 32, 95, 12, 39, 32, 11, 71, 70, 66]
   output: [1, 2, 0, 3, 0, 0, 1, 2, 0, 1]
*/
void binsBy10Count(std::vector<double> const& x, std::array<size_t, 10> &bins) {
    // Clear the output array
    bins.fill(0);

    const size_t N = x.size();

    // Each thread will accumulate in its own local array
    std::vector<std::array<size_t, 10>> threadLocal;
#pragma omp parallel
    {
        std::array<size_t, 10> local = {};
        #pragma omp for nowait schedule(static)
        for (size_t i = 0; i < N; ++i) {
            // integer division truncates toward zero; casting to size_t gives the bin index
            const size_t bin = static_cast<size_t>(x[i]) / 10;
            ++local[bin];
        }
        #pragma omp critical
        {
            // Merge local counts into the global result
            for (size_t b = 0; b < 10; ++b)
                bins[b] += local[b];
        }
    }
}
