struct COOElement {
    size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
   Example:
   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
   output: y=[2, 3]
*/
inline void spmv(double alpha,
                 const std::vector<COOElement> &A,
                 const std::vector<double> &x,
                 double beta,
                 std::vector<double> &y,
                 size_t M,
                 size_t N)
{
    // Scale y by beta in parallel
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    // Accumulate sparse matrix product in parallel
    #pragma omp parallel for schedule(dynamic, 256)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const COOElement &e = A[idx];
        if (e.row < M && e.column < N) {
            // atomic to avoid race conditions on same row
            #pragma omp atomic
            y[e.row] += alpha * e.value * x[e.column];
        }
    }
}
