bool reduceLogicalXOR(std::vector<bool> const& x) {
    // Empty vector → false
    if (x.empty()) return false;

    // Perform a parallel XOR reduction using OpenMP.
    // The vector<bool> implementation stores bits; accessing them individually
    // is still relatively cheap and allows the compiler to use efficient
