16_graph_largest_component:
```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <cstdint>

/*	Performance‑optimized implementation of largestComponent.
 *
 *	- Uses an iterative depth‑first search to avoid recursive
 *	  function call overhead.
 *	- Works with the supplied adjacency matrix in row‑major form.
 *  - Uses a packed byte vector for visited flags and a raw pointer
 *    to the adjacency data for maximum cache locality.
 */
inline int largestComponent(const std::vector<int>& A, std::size_t N) {
    // Visited array – 0 = unvisited, 1 = visited
    std::vector<uint8_t> visited(N, 0);
    const int* mat = A.data();

    int maxSize = 0;

    // Temporary stack for DFS – preallocate to avoid reallocations
    std::vector<std::size_t> stack;
    stack.reserve(N);

    for (std::size_t start = 0; start < N; ++start) {
        if (visited[start]) continue;

        int componentSize = 0;
        stack.clear();
        stack.push_back(start);
        visited[start] = 1;

        while (!stack.empty()) {
            std::size_t node = stack.back();
            stack.pop_back();
            ++componentSize;

            // Row pointer offset
            const int* row = mat + node * N;
            for (std::size_t col = 0; col < N; ++col) {
                if (row[col] && !visited[col]) {
                    visited[col] = 1;
                    stack.push_back(col);
                }
            }
        }

        if (componentSize > maxSize) maxSize = componentSize;
    }

    return maxSize;
}
