#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* Compute the discrete fourier transform of x. Store the result in output.
   Example:
   input: [1, 4, 9, 16]
   output: [30+0i, -8-12i, -10-0i, -8+12i]
*/
inline void dft(const std::vector<double> &x, std::vector<std::complex<double>> &output) {
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Parallelised over output elements (k)
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        const double angle = 2.0 * M_PI * k / N;
        const std::complex<double> w(std::cos(-angle), std::sin(-angle));   // exp(-i*2πk/N)
        std::complex<double> wk(1.0, 0.0); // w^0
        std::complex<double> sum(0.0, 0.0);

        for (int n = 0; n < N; ++n) {
            sum += x[n] * wk;
            wk *= w;                                  // multiply by w for next n
        }
        output[k] = sum;
    }
}
