#pragma once
#include <vector>
#include <cstdint>
#include <cstring>

/* Count the number of connected components in an undirected graph.
   The graph is given as a row‑major NxN adjacency matrix `A` of `int`.
   The routine is optimized for modern x86‑64 with gcc‑O2 and uses
   an iterative depth‑first search to eliminate function recursion
   overhead. It also employs a compact `bool` array for the visited
   flags and a pre‑allocated stack to avoid per‑iteration heap
   allocations.  The algorithm remains identical in behaviour to the
   original reference implementation. */
int componentCount(std::vector<int> const& A, size_t N)
{
    // If the graph is empty, there are no components.
    if (N == 0) return 0;

    // Vector of flags – compact form (1 byte per entry).
    std::vector<uint8_t> visited(N, 0);

    // Pre‑allocate a stack large enough for the worst case.
    // The stack holds indices of vertices that must be processed.
    std::vector<size_t> stack;
    stack.reserve(N);

    int compCount = 0;

    for (size_t start = 0; start < N; ++start)
    {
        if (visited[start]) continue;

        // New component found.
        ++compCount;
        visited[start] = 1;
        stack.push_back(start);

        // Standard iterative DFS.
        while (!stack.empty())
        {
            size_t v = stack.back();
            stack.pop_back();

            // Scan the whole row for adjacent vertices.
            const int* row = A.data() + v * N;   // pointer to the beginning of row v
            for (size_t j = 0; j < N; ++j)
            {
                // Inline the adjacency test and visited check.
                if (row[j] && !visited[j])
                {
                    visited[j] = 1;
                    stack.push_back(j);
                }
            }
        }
    }

    return compCount;
}
