    const std::size_t blockSize = 1024;          // tune if needed
    const std::size_t numBlocks = (n + blockSize - 1) / blockSize;

    std::vector<int64_t> blockSum(numBlocks, 0);

    // First pass: compute partial sums per block in parallel
#pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < numBlocks; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);
        int64_t s = 0;
        for (std::size_t i = start; i < end; ++i) {
            s += x[i];
            output[i] = s;               // temporary partial prefix
        }
        blockSum[b] = s;
    }

    // Reduce block sums to get offsets for each block (serial is fine, blocks << threads)
    for (std::size_t b = 1; b < numBlocks; ++b) {
        blockSum[b] += blockSum[b - 1];
    }

    // Second pass: add the offset from previous blocks
#pragma omp parallel for schedule(static)
    for (std::size_t b = 1; b < numBlocks; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);
        const int64_t offset = blockSum[b - 1];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
