   output: 2
*/
double closestPair(std::vector<double> const& x) {
    // Handle trivial cases fast
    size_t n = x.size();
    if (n < 2) return 0.0;

    // Work on a sorted copy – sorting is O(n log n), far cheaper than O(n²)
    std::vector<double> sorted(x);
    std::sort(sorted.begin(), sorted.end());

    double minDist = std::numeric_limits<double>::max();

    // In a sorted array, the minimum distance occurs between neighboring elements
    for (size_t i = 1; i < n; ++i) {
