/*
 * Compute one iteration of a 3‑point 1‑D Jacobi stencil.
 * Each element of `input` will be averaged with its two neighbours
 * and stored in the corresponding element of `output`.
 *
 * output[i] = (input[i-1] + input[i] + input[i+1]) / 3
 * (boundary neighbours are treated as zero).
 */
inline void jacobi1D(const std::vector<double>& input, std::vector<double>& output)
{
    const std::size_t N = input.size();
    if (N != output.size())
        output.resize(N);

    /* Parallelise over the outer loop.  
     * OpenMP will split the range into contiguous chunks,
     * which keeps the output vector cache‑friendly. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        double sum = input[i];          // centre element

        if (i > 0)
            sum += input[i - 1];        // left neighbour

        if (i + 1 < N)
            sum += input[i + 1];        // right neighbour

        output[i] = sum / 3.0;          // divide by a constant
    }
}
