49_sparse_la_sparse_lu_decomp:
```cpp
#pragma once
#include <vector>

struct COOElement {
    size_t row, column;
    double value;
};

/* Factorize the sparse matrix A into A = LU where L is a lower triangular
   matrix and U is an upper triangular matrix. A is a sparse NxN matrix
   stored in COO format. L and U are NxN matrices in row-major.
   The routine preserves the exact semantics of the original implementation.
 */
inline void luFactorize(
    const std::vector<COOElement> &A,
    std::vector<double> &L,
    std::vector<double> &U,
    size_t N)
{
    // Allocate dense representations for A, L and U
    std::vector<double> Afull(N * N, 0.0);
    L.assign(N * N, 0.0);        // initialize L to zeros
    U.assign(N * N, 0.0);        // initialize U to zeros

    // Populate the dense matrix from COO entries
    for (const auto &e : A) {
        Afull[e.row * N + e.column] = e.value;
    }

    // Perform Doolittle LU factorization (L has unit diagonal)
    for (size_t i = 0; i < N; ++i) {
        const double *AuRow = &Afull[i * N];
        double *Lrow = &L[i * N];
        double *Urow = &U[i * N];

        // Compute U[i][j] for j >= i
        for (size_t j = i; j < N; ++j) {
            double sum = AuRow[j];
            for (size_t k = 0; k < i; ++k)
                sum -= Lrow[k] * U[k * N + j];
            Urow[j] = sum;
        }

        // Compute L[i][j] for j < i
        for (size_t j = 0; j < i; ++j) {
            double sum = AuRow[j];
            for (size_t k = 0; k < j; ++k)
                sum -= Lrow[k] * U[k * N + j];
            Lrow[j] = sum / U[j * N + j];
        }

        // Unit diagonal of L
        Lrow[i] = 1.0;
    }
}
