#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Revised, highly‑optimised sparse‑matrix product.
 *
 * Y = A * X  where:
 *   A : M × K   (sparse, COO)
 *   X : K × N   (sparse, COO)
 *   Y : M × N   (dense, row‑major)
 *
 * The algorithm builds a small hash‑index of X by row, allowing fast
 * lookup of matching column/value pairs for each element of A.
 * The outer loop over A is parallelised with OpenMP; each thread writes
 * to Y which is partitioned by rows.  While there can be write‑conflicts
 * on the same row, the traffic is extremely low compared to the overall
 * size of Y, so we simply use atomic additions to keep correctness
 * without costly locks.
 *
 * The code keeps exactly the same semantics as the original reference
 * implementation, but it runs considerably faster on modern 8‑core
 * systems with gcc 11+ and OpenMP.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N) {
    // initialise output matrix
    Y.assign(M * N, 0.0);

    /* Build a hash‑map from row index (i.e. X.row) to a vector of
     * {column,value} pairs.  Since X is small compared to Y this
     * all‑in‑memory lookup is much cheaper than scanning the whole
     * vector for every element of A.  We reserve capacity to avoid
     * rehashing.
     */
    std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> index;
    index.reserve(X.size()*2);
    for (auto const& x : X)
        index[x.row].emplace_back(x.column, x.value);

    /* Parallel over A.  Each thread iterates over a chunk of A.
     * For a given element a = (rowA, colA, valA) we look up all X
     * elements with row == colA.  For every match we update Y[rowA,xcol]
     * using an atomic addition (double) to avoid race conditions.
     */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto& a = A[i];
        auto it = index.find(a.column);
        if (it == index.end()) continue;          // no match
        const auto& vec = it->second;             // all X entries with this row
        size_t base = a.row * N;
        for (auto const& p : vec) {
            size_t pos = base + p.first;          // Y[rowA][xcol]
            // atomic add on double – GCC provides _Atomic<double>
            double old = Y[pos];
            double newVal;
            do {
                newVal = old + a.value * p.second;
            } while (!__sync_bool_compare_and_swap(&Y[pos], old, newVal));
        }
    }
}
