#include <cstddef>
#include <limits>
#include <omp.h>

/*
 * Replace the i‑th element of the vector `x` with the minimum value
 * from indices `0` through `i`.  The implementation below performs a
 * parallel prefix (scan) using a two‑pass algorithm that works
 * efficiently on an x86‑64 machine with up to 8 threads and GCC
 * 9+ with OpenMP support.
 *
 * The code keeps the original semantics: after execution, `x[i]`
 * contains the minimum of `x[0] .. x[i]` for all `i`.  No data is
 * lost and the operation is deterministic.
 */
inline void partialMinimums(std::vector<float> &x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    /* Configuration ---------------------------------------------------------
     * Each thread works on a contiguous block.  The block size is chosen
     * so that the number of blocks does not exceed the number of threads.
     */
    const int    maxThreads = std::min<int>(omp_get_max_threads(), 8);
    const std::size_t blockSize = (N + maxThreads - 1) / maxThreads;
    const std::size_t blocks    = (N + blockSize - 1) / blockSize;

    /* 1st pass: compute the minimum of each block. ------------------------ */
    std::vector<float> blockMins(blocks, std::numeric_limits<float>::max());

    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blocks; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, N);
        float m = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i)
            if (x[i] < m) m = x[i];
        blockMins[b] = m;
    }

    /* Compute prefix minima of the block minima. ------------------------- */
    for (std::size_t b = 1; b < blocks; ++b)
        if (blockMins[b] > blockMins[b-1]) blockMins[b] = blockMins[b-1];

    /* 2nd pass: each thread updates its block using the prefix minimums. */
    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blocks; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, N);

        /* The first element of the block must also consider the minimum
         * preceding its block.  For the very first block this is simply
         * its current value.
         */
        const float preMin = (b == 0) ? std::numeric_limits<float>::max()
                                      : blockMins[b-1];

        float curMin = preMin;
        for (std::size_t i = start; i < end; ++i) {
            float v = x[i];
            if (v < curMin) curMin = v;
            x[i] = curMin;
        }
    }
}
