#include <algorithm>
#include <cstddef>

struct Point {
    double x, y;
};

/* Computes the convex hull of `points` using the monotone chain
   algorithm (O(n log n)).  The result is written to `hull`.
   The function preserves exact behaviour of the reference
   implementation but is tuned for speed on an 8‑thread
   x86‑64 machine compiled with GCC –O2 –fopenmp. */
static inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

static inline void convexHull(std::vector<Point> const& points,
                              std::vector<Point> &hull) {
    /* Fast path: <3 points ⇒ hull is the input itself */
    size_t n = points.size();
    if (n < 3) {
        hull = points;
        return;
    }

    /* Copy points and sort in place */
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) noexcept {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    /* Allocate workspace for both lower and upper hulls */
    std::vector<Point> tmp;
    tmp.reserve(2 * n);

    /* Build lower hull */
    for (size_t i = 0; i < n; ++i) {
        while (tmp.size() >= 2 &&
               cross(tmp[tmp.size() - 2], tmp[tmp.size() - 1], pts[i]) <= 0.0)
            tmp.pop_back();
        tmp.push_back(pts[i]);
    }

    /* Build upper hull – skip the first and last point of the lower hull */
    size_t lowerSize = tmp.size();
    for (size_t i = n; i-- > 1; ) {          // i = n-1 … 1
        while (tmp.size() > lowerSize + 1 &&
               cross(tmp[tmp.size() - 2], tmp[tmp.size() - 1], pts[i - 1]) <= 0.0)
            tmp.pop_back();
        tmp.push_back(pts[i - 1]);
    }

    /* Remove the redundant last point (same as first) */
    if (!tmp.empty())
        tmp.pop_back();

    hull = std::move(tmp);
}
