    for (size_t idx = 0; idx < A.size(); ++idx) {
        size_t r = A[idx].row;
        size_t c = A[idx].column;
        matrix[r * N + c] = A[idx].value;    // overwrites, same as original
    }

    // 3. Work copy of b
    std::vector<double> b_copy = b;
    x.assign(N, 0.0);

    // 4. Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // ------- Pivot selection -------
        double maxAbs = std::abs(matrix[i * N + i]);
        size_t pivotRow = i;
        for (size_t r = i + 1; r < N; ++r) {
            double val = std::abs(matrix[r * N + i]);
            if (val > maxAbs) {
                maxAbs = val;
                pivotRow = r;
            }
        }

        // Swap rows if necessary
        if (pivotRow != i) {
            #pragma omp parallel for schedule(static)
            for (size_t c = i; c < N; ++c) {
                std::swap(matrix[pivotRow * N + c], matrix[i * N + c]);
            }
            std::swap(b_copy[pivotRow], b_copy[i]);
        }

        // ------- Eliminate below -------
        double diag = matrix[i * N + i];
        // Protect division by zero (should not happen in original code)
        if (diag == 0.0) continue;

        #pragma omp parallel for schedule(static)
        for (size_t r = i + 1; r < N; ++r) {
            double factor = -matrix[r * N + i] / diag;
            for (size_t c = i; c < N; ++c) {
                if (c == i) {
                    matrix[r * N + c] = 0.0;   // explicitly zero
                } else {
                    matrix[r * N + c] += factor * matrix[i * N + c];
                }
            }
            b_copy[r] += factor * b_copy[i];
        }
    }

    // 5. Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double diag = matrix[i * N + i];
        // Again, avoid division by zero
        x[i] = (diag == 0.0) ? 0.0 : b_copy[i] / diag;
        for (int r = i - 1; r >= 0; --r) {
            b_copy[r] -= matrix[r * N + i] * x[i];
        }
    }
}
