#pragma once
#include <vector>
#include <omp.h>

/* Iterative LU factorisation (no pivoting)
 * A is stored in row-major order.
 * An NxN matrix is factorised into L (storage in the strict lower part)
 * and U (storage in the diagonal and upper part).  The algorithm
 * performs the same computations as the reference implementation, but
 * is tuned for modern x86‑64 CPUs with 8 logical cores.
 */
inline void luFactorize(std::vector<double> &A, size_t N) {
#pragma omp parallel for schedule(static)
    for (size_t k = 0; k < N; ++k) {
        const double A_kk = A[k * N + k];
        // Work on rows below the pivot row.
        for (size_t i = k + 1; i < N; ++i) {
            // The factor for this row, as in the textbook algorithm.
            const double factor = A[i * N + k] / A_kk;
            A[i * N + k] = factor;              // store L(i,k)

            // Update the remainder of the row with a vectorised inner loop.
            const double *row_k = &A[k * N];     // U(k, :)
            double *row_i = &A[i * N];
            size_t j = k + 1;
            // Process 4 columns at a time for better cache utilisation.
            for (; j + 3 < N; j += 4) {
                row_i[j]   -= factor * row_k[j];
                row_i[j+1] -= factor * row_k[j+1];
                row_i[j+2] -= factor * row_k[j+2];
                row_i[j+3] -= factor * row_k[j+3];
            }
            // Handle any remaining columns.
            for (; j < N; ++j) {
                row_i[j] -= factor * row_k[j];
            }
        }
    }
}
