#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

struct Point
{
    double x, y;
};

/*--------------- Helper functions ---------------*/
inline double sq(double v) { return v * v; }

inline double dist(const Point& a, const Point& b)
{
    // use std::hypot for accuracy and speed
    return std::hypot(b.x - a.x, b.y - a.y);
}

inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/*--------------- Main routine ---------------*/
double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    /* sort by x, then y */
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b)
              { return a.x < b.x || (a.x == b.x && a.y < b.y); });

    /* build hull in a pre‑allocated vector (max 2n points) */
    std::vector<Point> hull(2 * n);
    int k = 0;

    /* lower hull */
    for (std::size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0) --k;
        hull[k++] = sorted[i];
    }

    /* upper hull */
    for (std::size_t i = n - 1, t = k + 1; i > 0; --i)
    {
        while (k >= t && cross(hull[k - 2], hull[k - 1], sorted[i - 1]) <= 0.0) --k;
        hull[k++] = sorted[i - 1];
    }

    hull.resize(k - 1);          // last point equal to first, remove duplicate

    /* sum distances – parallelizable */
    double perimeter = 0.0;
    const std::size_t m = hull.size();

    /* use OpenMP parallel for with reduction */
    #pragma omp parallel for reduction(+:perimeter)
    for (std::size_t i = 0; i < m; ++i)
    {
        const std::size_t j = (i + 1) % m;
        perimeter += dist(hull[i], hull[j]);
    }

    return perimeter;
}
