#define M_PI 3.14159265358979323846
#endif

/* In‑place iterative radix‑2 Cooley‑Tukey FFT.
   The output vector is overridden with the DFT of the input.
   The routine is fully parallelised with OpenMP and preserves the
   exact numerical behaviour of the original implementation. */
static inline void fft(std::vector<std::complex<double>> const& x,
                       std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.assign(x.begin(), x.end());                // copy input

    /* --------- iterative butterfly stages --------- */
    std::size_t m = 0;                                 // number of stages
    for (std::size_t t = N; t > 1; t >>= 1) ++m;

    /* pre‑compute the principal twiddle factor angle */
    const double theta = M_PI / N;

#pragma omp parallel
    {
        std::complex<double> phiT, T, t;
        std::size_t k, n, l, a, b;
        #pragma omp for schedule(static)
        for (std::size_t stage = 0; stage < m; ++stage) {
            k = 1U << stage;                     // 2^stage
            n = k << 1;                          // 2^(stage+1)
            phiT = std::exp(-std::complex<double>(0.0, theta * (1ULL << stage)));
            T    = 1.0;
            for (l = 0; l < k; ++l) {
                for (a = l; a < N; a += n) {
                    b = a + k;
                    t  = output[a] - output[b];
                    output[a] += output[b];
                    output[b] = t * T;
                }
                T *= phiT;
            }
        }
    }

    /* --------- bit‑reversal permutation --------- */
    const std::size_t bitmask = (1U << m) - 1;
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        j = (j >> 1) | ((j & 1) << 31);
        j = (j >> 2) | ((j & 3) << 30);
        j = (j >> 4) | ((j & 15) << 28);
        j = (j >> 8) | ((j & 255) << 24);
        j = (j >> 16) | ((j & 65535) << 16);
        j >>= (32 - m);
        if (j > i) std::swap(output[i], output[j]);
    }
}
