#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <cmath>

struct Point {
    double x, y;
};

inline double dist_sq(const Point& a, const Point& b) {
    double dx = a.x - b.x, dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// Helper to compute minimum distance in a strip
static inline double strip_min(const std::vector<Point>& strip, double d) {
    double min_d = d;
    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < min_d; ++j) {
            double d_sq = dist_sq(strip[i], strip[j]);
            if (d_sq < min_d * min_d) {
                min_d = std::sqrt(d_sq);
            }
        }
    }
    return min_d;
}

// Recursive divide‑and‑conquer
static double closest_pair_rec(std::vector<Point>& pts_by_x,
                               std::vector<Point>& pts_by_y,
                               size_t left, size_t right) {
    size_t n = right - left;
    if (n <= 3) {
        double min_d = std::numeric_limits<double>::max();
        for (size_t i = left; i < right; ++i)
            for (size_t j = i + 1; j < right; ++j)
                min_d = std::min(min_d, std::sqrt(dist_sq(pts_by_x[i], pts_by_x[j])));
        return min_d;
    }

    size_t mid = left + n / 2;
    double midx = pts_by_x[mid].x;

    std::vector<Point> left_y, right_y;
    left_y.reserve(mid - left);
    right_y.reserve(right - mid);
    for (const auto& p : pts_by_y) {
        if (p.x <= midx) left_y.push_back(p);
        else right_y.push_back(p);
    }

    double dl = closest_pair_rec(pts_by_x, left_y, left, mid);
    double dr = closest_pair_rec(pts_by_x, right_y, mid, right);
    double d = std::min(dl, dr);

    std::vector<Point> strip;
    strip.reserve(n);
    for (const auto& p : pts_by_y) {
        if (std::fabs(p.x - midx) < d) strip.push_back(p);
    }

    return std::min(d, strip_min(strip, d));
}

double closestPair(std::vector<Point> const& points) {
    if (points.size() < 2) return 0.0;

    std::vector<Point> pts_by_x(points.begin(), points.end());
    std::sort(pts_by_x.begin(), pts_by_x.end(),
              [](const Point& a, const Point& b) { return a.x < b.x; });

    std::vector<Point> pts_by_y = pts_by_x;
    std::sort(pts_by_y.begin(), pts_by_y.end(),
              [](const Point& a, const Point& b) { return a.y < b.y; });

    return closest_pair_rec(pts_by_x, pts_by_y, 0, pts_by_x.size());
}
