    values.reserve(x.size());
    std::vector<std::size_t> positions;
    positions.reserve(x.size());

    // Collect non‑zero values and their original indices
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0) {
            values.push_back(x[i]);
            positions.push_back(i);
