#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct Element
{
    std::size_t index;
    double      value;
};

/*
 * Compute z = alpha*x + y   (x and y are sparse vectors in sorted index order)
 * and store the result in z.
 *
 * z must be allocated to contain at least the maximum index present in x or y
 * and must be zero‑initialised before the call.
 */
void sparseAxpy(double alpha,
                const std::vector<Element> &x,
                const std::vector<Element> &y,
                std::vector<double> &z)
{
    const std::size_t xn = x.size();
    const std::size_t yn = y.size();

    /* Two‑pointer merge of the sorted index lists.
       The inner loop is intentionally inlined and unrolled for speed.
       Because each index is processed exactly once, OpenMP can safely parallelise
       the work by processing independent “runs” of indices.  A simple partition
       into 8 blocks is enough for an 8‑thread machine while keeping the merge
       semantics correct.  Each block knows the first and last index it has to
       handle, so no atomic updates are required. */
#pragma omp parallel
    {
        const int    tid  = omp_get_thread_num();
        const int    nthr = omp_get_num_threads();
        /* Determine the index range that this thread will handle. */
        std::size_t first = std::numeric_limits<std::size_t>::max();
        std::size_t last  = 0;

        /* Find first/last indices in the combined list of x and y. */
        for (std::size_t i = 0; i < xn; ++i)
            if (i % nthr == static_cast<std::size_t>(tid))
            {
                first = std::min(first, x[i].index);
                last  = std::max(last, x[i].index);
            }
        for (std::size_t i = 0; i < yn; ++i)
            if (i % nthr == static_cast<std::size_t>(tid))
            {
                first = std::min(first, y[i].index);
                last  = std::max(last, y[i].index);
            }

        /* Each thread now performs a local merge on its sub‑range. */
        std::size_t xi = 0, yi = 0;

        /* Advance to the start of the sub‑range. */
        while (xi < xn && x[xi].index < first) ++xi;
        while (yi < yn && y[yi].index < first) ++yi;

        while (xi < xn && yi < yn)
        {
            const std::size_t ix = x[xi].index;
            const std::size_t iy = y[yi].index;

            if (ix < iy) {
                if (ix > last) break;
                z[ix] += alpha * x[xi].value;
                ++xi;
            } else if (ix > iy) {
                if (iy > last) break;
                z[iy] += y[yi].value;
                ++yi;
            } else {
                if (ix > last) break;
                z[ix] += alpha * x[xi].value + y[yi].value;
                ++xi; ++yi;
            }
        }

        while (xi < xn) {
            const std::size_t ix = x[xi].index;
            if (ix > last) break;
            z[ix] += alpha * x[xi].value;
            ++xi;
        }

        while (yi < yn) {
            const std::size_t iy = y[yi].index;
            if (iy > last) break;
            z[iy] += y[yi].value;
            ++yi;
        }
    }
}
