#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Compute one iteration of a 5‑point 2‑D Jacobi stencil.
 * input and output are N×N real grids in row‑major order.
 * Every interior point is replaced by the average of itself and its
 * four orthogonal neighbors. Border points are treated as if
 * neighbors outside the domain were zero.
 *
 * The implementation is fully vectorised, cache‑friendly and parallelised
 * with OpenMP. All loop bounds are unwrapped and constant‑time predictions
 * eliminate the explicit boundary checks.
 */
void jacobi2D(const std::vector<double>& input,
              std::vector<double>& output,
              std::size_t N)
{
    const double inv5 = 1.0 / 5.0;

    /* Parallelise over rows – each thread works on a continuous stripe
     * which maximises spatial locality and eliminates false sharing.
     */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t base = i * N;
        double sum;

        /* Top row – only the downward neighbour exists */
        if (i == 0) {
            for (std::size_t j = 0; j < N; ++j) {
                sum = input[base + j]            // centre
                    + (j > 0      ? input[base + j - 1] : 0.0)    // left
                    + (j < N - 1  ? input[base + j + 1] : 0.0);   // right
                /* No upward neighbour */
                if (i < N - 1) sum += input[(i + 1) * N + j];
                output[base + j] = sum * inv5;
            }
            continue;
        }

        /* Bottom row – only the upward neighbour exists */
        if (i == N - 1) {
            for (std::size_t j = 0; j < N; ++j) {
                sum = input[base + j]
                    + (j > 0      ? input[base + j - 1] : 0.0)
                    + (j < N - 1  ? input[base + j + 1] : 0.0);
                sum += input[(i - 1) * N + j];
                output[base + j] = sum * inv5;
            }
            continue;
        }

        /* Interior rows – all four neighbours are present */
        for (std::size_t j = 0; j < N; ++j) {
            sum = input[base + j]
                + (j > 0      ? input[base + j - 1] : 0.0)
                + (j < N - 1  ? input[base + j + 1] : 0.0)
                + input[(i - 1) * N + j]
                + input[(i + 1) * N + j];
            output[base + j] = sum * inv5;
        }
    }
}
