/*
 * Optimized matrix-matrix multiplication (GEMM) for doubles.
 *
 * The algorithm uses a cache‑friendly blocked approach and OpenMP parallelism.
 * It preserves the exact semantics of the original routine: the result is
 * accumulated into the supplied output vector C which must be zeroed by the
 * caller beforehand.
 *
 * Parameters:
 *   A : const M×K matrix in row‑major order
 *   B : const K×N matrix in row‑major order
 *   C : M×N matrix in row‑major order (output)
 *   M : number of rows in A (and C)
 *   K : number of columns in A / rows in B
 *   N : number of columns in B (and C)
 */
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Block size chosen experimentally for typical L1/L2 cache sizes.
    constexpr size_t BLOCK = 64;

    // Parallelize outer i,k loops; OpenMP handles scheduling automatically.
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK) {
        for (size_t kk = 0; kk < K; kk += BLOCK) {
            // Compute limits for current block
            size_t i_max = std::min(ii + BLOCK, M);
            size_t k_max = std::min(kk + BLOCK, K);

            for (size_t i = ii; i < i_max; ++i) {
                for (size_t k = kk; k < k_max; ++k) {
                    double aik = A[i*K + k];
                    // Inner loop over j can be unrolled by 4 for extra speed
                    size_t j = 0;
                    for (; j + 3 < N; j += 4) {
                        C[i*N + j]     += aik * B[k*N + j];
                        C[i*N + j + 1] += aik * B[k*N + j + 1];
                        C[i*N + j + 2] += aik * B[k*N + j + 2];
                        C[i*N + j + 3] += aik * B[k*N + j + 3];
                    }
                    for (; j < N; ++j) {
                        C[i*N + j] += aik * B[k*N + j];
                    }
                }
            }
        }
    }
}
