                              std::vector<double>& x,
                              size_t N)
{
    // Ensure output vector has the right size
    if (x.size() != N) x.resize(N, 0.0);

    // Work on copies to keep the original data untouched
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    // Gaussian elimination – forward elimination
    for (size_t i = 0; i + 1 < N; ++i) {
        double pivot = A_copy[i * N + i];
        if (pivot == 0.0) {               // Preserve original behaviour
            return;
        }

        // Parallelise the elimination of rows below pivot
#pragma omp parallel for schedule(dynamic)
        for (long long j = static_cast<long long>(i + 1); j < static_cast<long long>(N); ++j) {
            double factor = A_copy[j * N + i] / pivot;
            // Update the rest of the row
            for (size_t k = i; k < N; ++k) {
                A_copy[j * N + k] -= factor * A_copy[i * N + k];
            }
            // Update RHS
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution – single thread for simplicity and to avoid race conditions
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j) {
            sum += A_copy[i * N + j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / A_copy[i * N + i];
    }
}
