    // Otherwise it falls back to the regular std::sort.
#ifdef _GLIBCXX_PARALLEL
    __gnu_parallel::sort(indices.begin(), indices.end(), cmp);
#else
    std::sort(indices.begin(), indices.end(), cmp);
#endif

    // Write the resulting ranks into the output vector.
    // The assignment is embarrassingly parallel – we can dispatch it in chunks.
    const std::size_t block = 1 << 20;  // 1M elements per block, tune if needed
    std::size_t i = 0;
#pragma omp parallel
    {
        std::size_t local_i = i;
#pragma omp for schedule(static, block)
        for (std::size_t j = 0; j < indices.size(); ++j) {
            ranks_[indices[j]] = j;
        }
    }
