/*
 * Game of Life – one generation.
 * Parameters
 *   input  – read‑only NxN grid (row‑major). 0/1 values.
 *   output – write‑only NxN grid (row‑major). 0/1 values.
 *   N      – dimension of the grid.
 */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int>& output,
                       size_t N) noexcept
{
    // Allow OpenMP to use all available threads
    constexpr int MaxThreads = 8;

    // Use raw pointers for speed
    const int*  inp = input.data();
    int*        out = output.data();

    // Parallel outer loop – each thread handles a stripe of rows
#pragma omp parallel for schedule(static) num_threads(MaxThreads)
    for (size_t i = 0; i < N; ++i) {
        const size_t rowBase = i * N;
        const size_t rowPrev = (i > 0)      ? (i - 1) * N : size_t(-1);
        const size_t rowNext = (i + 1 < N)  ? (i + 1) * N : size_t(-1);

        for (size_t j = 0; j < N; ++j) {
            int sum = 0;
            // Direct neighbour access – avoids branch misprediction
            if (rowPrev != size_t(-1)) sum += inp[rowPrev + j];
            if (rowNext != size_t(-1)) sum += inp[rowNext + j];
            if (j > 0)               sum += inp[rowBase + j - 1];
            if (j + 1 < N)           sum += inp[rowBase + j + 1];
            if (rowPrev != size_t(-1) && j > 0)
                sum += inp[rowPrev + j - 1];
            if (rowPrev != size_t(-1) && j + 1 < N)
                sum += inp[rowPrev + j + 1];
            if (rowNext != size_t(-1) && j > 0)
                sum += inp[rowNext + j - 1];
            if (rowNext != size_t(-1) && j + 1 < N)
                sum += inp[rowNext + j + 1];

            const int cur = inp[rowBase + j];
            out[rowBase + j] = (cur == 1) ?
                                ((sum == 2 || sum == 3) ? 1 : 0) :
                                (sum == 3 ? 1 : 0);
        }
    }
}
