#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/*
   In‑place radix‑2 Cooley‑Tukey FFT (decimation‑in‑frequency),
   written for maximum speed on a modern x86‑64 compiler with
   OpenMP support.  The algorithm:
      1. Allocate a table of pre‑computed twiddle factors.
      2. Perform the butterfly stages in a naïve
         “index‑wise” order (which is fast due to locality).
      3. Finish with a simple bit‑reversal permutation.
   The code keeps the same semantics as the original
   reference implementation – the output vectors `r` and `i`
   are filled with the real and imaginary parts of the
   transform of `x` in the order specified by the test harness.
 */

/*------------------------------------------------------------*/
/* Helper: number of leading zeros of a 32‑bit unsigned int  */
/*------------------------------------------------------------*/
static inline unsigned int clz32(uint32_t x) {
#if defined(__GNUC__) || defined(__clang__)
    return x ? __builtin_clz(x) : 32;
#else
    unsigned int n = 0;
    while ((x & 0x80000000u) == 0) { x <<= 1; ++n; }
    return n;
#endif
}

/*------------------------------------------------------------*/
/* In‑place bit reversal for an array of size N = 2^m         */
/*------------------------------------------------------------*/
static void bit_reverse(std::complex<double> *data, unsigned int N, unsigned int m) {
    for (unsigned int i = 0; i < N; ++i) {
        unsigned int j = ((i & 0x55555555u) << 1) | ((i & 0xaaaaaaaau) >> 1);
        j = ((j & 0x33333333u) << 2) | ((j & 0xccccccccu) >> 2);
        j = ((j & 0x0f0f0f0fu) << 4) | ((j & 0xf0f0f0f0u) >> 4);
        j = ((j & 0x00ff00ffu) << 8) | ((j & 0xff00ff00u) >> 8);
        j = (j >> 16) | (j << 16);
        j >>= 32 - m;
        if (j > i) {
            std::complex<double> temp = data[i];
            data[i] = data[j];
            data[j] = temp;
        }
    }
}

/*------------------------------------------------------------*/
/* Fast Fourier Transform                                         */
/*------------------------------------------------------------*/
void fft(const std::vector<std::complex<double>>& x,
         std::vector<double>& r, std::vector<double>& i) {
    const unsigned int N = static_cast<unsigned int>(x.size());
    const unsigned int m = 32 - clz32(N);          // log2(N)
    std::vector<std::complex<double>> data(x);     // make a copy

    /* 1. Pre‑compute twiddle factor table */
    std::vector<std::complex<double>> twiddle;
    twiddle.reserve(m);
    for (unsigned int stage = 0; stage < m; ++stage) {
        unsigned int span = 1u << stage;
        double angle = -M_PI / static_cast<double>(span);
        twiddle.emplace_back(std::cos(angle), std::sin(angle));
    }

    /* 2. Butterfly stages (radix‑2, iteratively) */
    for (unsigned int stage = 0; stage < m; ++stage) {
        unsigned int span = 1u << stage;               // butterfly span
        unsigned int half = span >> 1;                 // half‑span
        std::complex<double> w = std::complex<double>(1.0, 0.0);
        double theta = -M_PI / static_cast<double>(half);
        std::complex<double> w_phase(std::cos(theta), std::sin(theta));

        for (unsigned int k = 0; k < half; ++k) {
            std::complex<double> wk = w;
            /* Each sub‑array of size 2*half is processed in a parallel loop */
            #pragma omp parallel for schedule(static)
            for (unsigned int j = k; j < N; j += 2 * half) {
                std::complex<double> t = wk * data[j + half];
                data[j + half] = data[j] - t;
                data[j] += t;
            }
            w *= w_phase;
        }
    }

    /* 3. Bit‑reversal permutation */
    bit_reverse(data.data(), N, m);

    /* 4. Separate real/imag parts into the output vectors */
    for (unsigned int idx = 0; idx < N; ++idx) {
        r[idx] = data[idx].real();
        i[idx] = data[idx].imag();
    }
}
