// ---------- fast comparator using squared magnitude ----------
inline bool cmp_mag(const std::complex<double>* a, const std::complex<double>* b)
{
    // use norm to avoid sqrt; cheaper than std::abs
    double na = a->real() * a->real() + a->imag() * a->imag();
    double nb = b->real() * b->real() + b->imag() * b->imag();
    return na < nb;
}

void sortComplexByMagnitude(std::vector<std::complex<double>> &x)
{
    const size_t n = x.size();
    if (n <= 1) return;

    // 1. compute squared magnitudes in parallel
    std::vector<double> norms(n);
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        const auto &c = x[i];
        norms[i] = c.real() * c.real() + c.imag() * c.imag();
    }

    // 2. create index array and sort by magnitude
    std::vector<size_t> idx(n);
    for (size_t i = 0; i < n; ++i) idx[i] = i;

    std::sort(idx.begin(), idx.end(),
              [&](size_t a, size_t b) { return norms[a] < norms[b]; });

    // 3. reorder original vector according to sorted indices
    std::vector<std::complex<double>> tmp = std::move(x);
    for (size_t i = 0; i < n; ++i) {
        x[i] = std::move(tmp[idx[i]]);
    }
}
