// In‐place radix‑2 decimation‑in‑time FFT
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    // Bit reversal permutation (in parallel)
    std::jthread rev([&]() {
        std::vector<std::size_t> revIdx(N);
        for (std::size_t i = 0; i < N; ++i) {
            std::size_t j = i;
            j = ((j & 0xaaaaaaaau) >> 1) | ((j & 0x55555555u) << 1);
            j = ((j & 0xccccccccu) >> 2) | ((j & 0x33333333u) << 2);
            j = ((j & 0xf0f0f0f0u) >> 4) | ((j & 0x0f0f0f0fu) << 4);
            j = ((j & 0xff00ff00u) >> 8) | ((j & 0x00ff00ffu) << 8);
            j = ((j >> 16) | (j << 16)) >> (32 - static_cast<unsigned>(logN));
            revIdx[i] = j;
        }
        auto it = x.begin();
        std::for_each(std::execution::par_unseq, revIdx.begin(), revIdx.end(),
            [&](std::size_t j) {
                std::size_t i = &it[j] - &x[0];
                if (j > i) std::swap(x[i], x[j]);
            });
    });

    // Main FFT loop
    std::complex<double> theta = std::complex<double>(0, -2.0 * M_PI / static_cast<double>(N));
    std::complex<double> w_m = std::exp(theta);          // w_N
    std::complex<double> w  = 1.0;                       // root of unity accumulator

    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m = 1ull << s;     // 2^s
        const std::size_t m2 = m >> 1;       // m/2
        const std::complex<double> wm = std::pow(w_m, static_cast<double>(N / m));

        for (std::size_t k = 0; k < m2; ++k) {
            const std::size_t j = k;
            const std::complex<double> w = std::pow(wm, static_cast<double>(j));
            std::for_each(std::execution::par_unseq,
                x.begin() + j,
                x.begin() + N,
                [&, j, m, w](std::complex<double>& a) {
                    const std::size_t t = (a - x[a - j]) * w;
                    a += x[a - j];
                    x[a - j] = t;
                });
        }
    }
}

// Inverse FFT in place
inline void ifft(std::vector<std::complex<double>>& x)
{
    // Conjugate, FFT, conjugate, scale
    std::transform(std::execution::par_unseq, x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v) { return std::conj(v); });

    fft_helper(x);

    std::transform(std::execution::par_unseq, x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v) { return std::conj(v); });

    const double invN = 1.0 / static_cast<double>(x.size());
    std::transform(std::execution::par_unseq, x.begin(), x.end(), x.begin(),
                   [invN](const std::complex<double>& v) { return v * invN; });
}
