#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <thread>
#include <algorithm>
#include <emmintrin.h>   // SSE2 intrinsics for speed
#include <immintrin.h>   // AVX2 intrinsics for speed

// Helper: bit-reversal in-place (iterative, parallelised)
static inline void bit_reverse_parallel(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    const unsigned int m = static_cast<unsigned int>(std::log2(N));

    // local lambda to swap two elements
    auto swap = [&](size_t i, size_t j)
    {
        std::complex<double> tmp = x[i];
        x[i] = x[j];
        x[j] = tmp;
    };

    // Parallel loop over the first half of indices
    const size_t num_threads = std::thread::hardware_concurrency();
    std::vector<std::thread> workers;
    workers.reserve(num_threads);

    auto worker = [&](size_t tid, size_t stride) {
        for (size_t i = tid; i < N / 2; i += stride) {
            size_t rev = i;
            rev = (((rev & 0xaaaaaaaaULL) >> 1) | ((rev & 0x55555555ULL) << 1));
            rev = (((rev & 0xccccccccULL) >> 2) | ((rev & 0x33333333ULL) << 2));
            rev = (((rev & 0xf0f0f0f0ULL) >> 4) | ((rev & 0x0f0f0f0fULL) << 4));
            rev = (((rev & 0xff00ff00ULL) >> 8) | ((rev & 0x00ff00ffULL) << 8));
            rev = ((rev >> 16) | (rev << 16));
            rev >>= (32 - m);
            if (rev > i) swap(i, rev);
        }
    };

    for (size_t t = 0; t < num_threads; ++t)
        workers.emplace_back(worker, t, num_threads);

    for (auto& th : workers) th.join();
}

// Helper: precompute twiddle factors
static inline std::vector<std::complex<double>> precompute_twiddles(size_t N)
{
    std::vector<std::complex<double>> w(N / 2);
    const double pi = std::acos(-1.0);
    for (size_t i = 0; i < N / 2; ++i)
        w[i] = std::exp(std::complex<double>(0.0, -2.0 * pi * static_cast<double>(i) / static_cast<double>(N)));
    return w;
}

// Main FFT implementation (iterative radix‑2, real‑to‑complex conjugate)
void fftConjugate(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    if (N <= 1) return;

    // Precompute twiddle factors
    const auto& w = precompute_twiddles(N);

    // Iterative radix‑2 FFT
    for (size_t len = 2; len <= N; len <<= 1)
    {
        const size_t half = len >> 1;
        const size_t step = N / len;
        // Main butterfly loop
        for (size_t i = 0; i < N; i += len)
        {
            // Vectorised butterfly using AVX2 (4 doubles per register)
            size_t j = i;
            size_t k = i + half;
            for (; j + 7 < k; j += 8, k += 8)
            {
                // Load real and imag parts interleaved
                __m256d aRe = _mm256_loadu_pd(&x[j].real());
                __m256d aIm = _mm256_loadu_pd(&x[j].imag());
                __m256d bRe = _mm256_loadu_pd(&x[k].real());
                __m256d bIm = _mm256_loadu_pd(&x[k].imag());

                // Compute twiddle index
                size_t idx = ((j - i) * step) % (N / 2);
                __m256d wRe = _mm256_set1_pd(std::real(w[idx]));
                __m256d wIm = _mm256_set1_pd(std::imag(w[idx]));

                // Multiply b by twiddle (b * w)
                __m256d tmpRe = _mm256_sub_pd(_mm256_mul_pd(bRe, wRe),
                                              _mm256_mul_pd(bIm, wIm));
                __m256d tmpIm = _mm256_add_pd(_mm256_mul_pd(bRe, wIm),
                                              _mm256_mul_pd(bIm, wRe));

                // Butterfly
                __m256d outRe_a = _mm256_add_pd(aRe, tmpRe);
                __m256d outIm_a = _mm256_add_pd(aIm, tmpIm);
                __m256d outRe_b = _mm256_sub_pd(aRe, tmpRe);
                __m256d outIm_b = _mm256_sub_pd(aIm, tmpIm);

                _mm256_storeu_pd(&x[j].real(), outRe_a);
                _mm256_storeu_pd(&x[j].imag(), outIm_a);
                _mm256_storeu_pd(&x[k].real(), outRe_b);
                _mm256_storeu_pd(&x[k].imag(), outIm_b);
            }

            // Scalar tail for remaining elements
            for (; j < k; ++j, ++k)
            {
                std::complex<double> a = x[j];
                std::complex<double> b = x[k];
                size_t idx = ((j - i) * step) % (N / 2);
                std::complex<double> t = b * w[idx];
                x[j] = a + t;
                x[k] = a - t;
            }
        }
    }

    // Bit-reversal reordering (parallelised)
    bit_reverse_parallel(x);

    // Conjugate all elements
    #pragma omp parallel for
    for (size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
